VALUES
  ('social-worker-moex-06250', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '我國人口老化發展快速，某協會想要採用德菲術（Delphi panel），邀請專家學者提供意見，來了解協會 從原本的青少年兒童服務機構轉型為老人長期照顧機構的利弊得失，請問該協會採取這個研究方法的優 點為何？', '["受邀的專家學者彼此具匿名性", "所有的成員可以面對面討論，容易聚焦", "進行一至二次就可以歸納出專家學者們的共識", "以訪談為主，問卷為輔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06251', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者欲分析某老人照顧關懷據點健康促進活動之滿意度，設計了一份問卷，對每一個問項均請作答 者自 0、1、2、3、4 選擇一個數字代表其「非常不滿意（0）」到「非常滿意（4）」的意見。請問這是 什麼測量尺度？', '["名義尺度（nominal measure）", "順序尺度（ordinal measure）", "等距尺度（interval measure）", "等比尺度（ratio measure）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06252', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於測量工具品質之判準，下列敘述何者錯誤？', '["信度與效度常用於判斷測量工具品質是否優良", "效度指的是測量工具能正確反映被測量概念的程度", "研究者可以使用測試－再測法（test-retest method）或折半法（split-half method）來檢測效度", "若量表之Cronbach’s α值高達0.9，則可用來解釋該量表之內部一致性信度高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06253', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為避免研究者對受試者產生霍桑效應（Hawthorne Effect），研究者在進行實驗設計時可考慮採用：', '["開放實驗設計", "單組前後測設計", "靜態組間比較設計", "雙盲實驗設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06254', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '實驗設計過程中若發生實驗刺激以外的因素影響了依變項，就會產生無效度的問題。例如原來受試者本 來就選取一些極端個案（例如成績極差、酗酒情況極嚴重），以致於實驗結果常出現高估實驗刺激效果 的情形，這是何種效應導致：', '["歷史效應（history effect）", "成熟效應（maturation effect）", "統計迴歸效應（statistical regression effect）", "補償效應（compensation effect）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06255', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列關於內容分析法（content analysis）的敘述，何者錯誤？', '["內容分析法最常使用的分析單位為家庭或個人", "內容分析法必須針對其研究單位之內容進行編碼", "內容分析雖多運用於量化研究中，但亦有質性研究採用此法", "相較於調查研究，內容分析法較為經濟與安全"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06256', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何種研究方法，研究者的功能在於作為研究對象的資源，為研究對象提供機會，使研究對象為其自 身利益採取有效行動？', '["民族誌（ethnography）", "個案研究（case study）", "參與式行動研究（participatory action research）", "俗民方法論（ethnomethodology）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06257', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '編碼（coding）是質化研究資料分析的一道關鍵程序，那一種編碼是質化資料分析中，最初步的概念分類 與標示？', '["選擇性編碼（selective coding）", "焦點性編碼（focused coding）", "主軸性編碼（axial coding）", "開放性編碼（open coding）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06258', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在實驗研究中，若實驗的結果無法概推至真實世界，我們稱之為：', '["內在無效度", "外在無效度", "內在無信度", "外在無信度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06259', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想經由前、後測成績的方式，瞭解一個由10人所組成的青少年成長團體之成效。得到數據如下： 前測平均數79分、後測平均數85分，t值＝2.52，p＝0.043（雙尾）。下列有關敘述，何者正確？', '["本研究採用的是雙樣本獨立t檢定", "在α=0.01的水準下，前後測有顯著差異", "在α=0.05的水準下，前後測有顯著差異，且後測比前測分數顯著較高", "在α=0.05的水準下，前後測有顯著差異，但後測分數並無顯著高於前測分數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
